// Initiate OIDC login
app.get('/auth/login', (req, res) => {
  // Generate state parameter for CSRF protection
  const state = crypto.randomBytes(32).toString('hex');
  // Generate nonce for replay protection
  const nonce = crypto.randomBytes(32).toString('hex');

  // Store state and nonce in session
  req.session.oauthState = state;
  req.session.oauthNonce = nonce;

  const authorizationUrl = new URL(OIDC_CONFIG.authorizationEndpoint);
  authorizationUrl.searchParams.set('response_type', 'code');
  authorizationUrl.searchParams.set('client_id', OIDC_CONFIG.clientId);
  authorizationUrl.searchParams.set('redirect_uri', OIDC_CONFIG.redirectUri);
  authorizationUrl.searchParams.set('scope', OIDC_CONFIG.scope);
  authorizationUrl.searchParams.set('state', state);
  authorizationUrl.searchParams.set('nonce', nonce);
  authorizationUrl.searchParams.set('prompt', 'consent');

  console.log(`Redirecting user to authorization endpoint: ${authorizationUrl.toString()}`);
  res.redirect(authorizationUrl.toString());
});

// OIDC callback handler
app.get('/auth/callback', async (req, res) => {
  const { code, state, error, error_description } = req.query;

  // Handle errors from the authorization server
  if (error) {
    console.error(`Authorization error: ${error} - ${error_description}`);
    return res.status(400).json({
      error: 'Authorization failed',
      details: error_description || error,
    });
  }

  // Verify authorization code is present
  if (!code) {
    return res.status(400).json({ error: 'Missing authorization code' });
  }

  // Verify state parameter to prevent CSRF
  if (!state || state !== req.session.oauthState) {
    console.error('State mismatch: possible CSRF attack');
    return res.status(403).json({ error: 'Invalid state parameter - possible CSRF attack' });
  }

  try {
    // Exchange authorization code for tokens
    console.log('Exchanging authorization code for tokens...');
    const tokenResponse = await exchangeCodeForTokens(code);

    const { access_token, id_token, refresh_token, token_type, expires_in } = tokenResponse;

    if (!id_token) {
      return res.status(400).json({ error: 'No id_token received from token endpoint' });
    }

    // Decode the id_token JWT to extract user information
    // WARNING: jwt.decode() does NOT verify the signature.
    // In production, you should use jwt.verify() with the provider's public keys (JWKS)
    // to ensure the token hasn't been tampered with.
    const decodedIdToken = jwt.decode(id_token, { complete: true });

    if (!decodedIdToken) {
      return res.status(400).json({ error: 'Failed to decode id_token' });
    }

    console.log('Decoded id_token header:', decodedIdToken.header);
    console.log('Decoded id_token payload:', decodedIdToken.payload);

    const idTokenClaims = decodedIdToken.payload;

    // Verify essential claims
    const claimsVerification = verifyIdTokenClaims(idTokenClaims);
    if (!claimsVerification.valid) {
      console.error('ID token claims verification failed:', claimsVerification.errors);
      return res.status(401).json({
        error: 'ID token validation failed',
        details: claimsVerification.errors,
      });
    }

    // Verify nonce to prevent replay attacks
    if (idTokenClaims.nonce && idTokenClaims.nonce !== req.session.oauthNonce) {
      console.error('Nonce mismatch: possible replay attack');
      return res.status(403).json({ error: 'Invalid nonce - possible replay attack' });
    }

    // Extract user information from id_token claims
    const userInfo = {
      sub: idTokenClaims.sub,
      email: idTokenClaims.email || null,
      emailVerified: idTokenClaims.email_verified || false,
      name: idTokenClaims.name || null,
      givenName: idTokenClaims.given_name || null,
      familyName: idTokenClaims.family_name || null,
      picture: idTokenClaims.picture || null,
      locale: idTokenClaims.locale || null,
    };

    // Optionally fetch additional user info from userinfo endpoint
    if (access_token) {
      const additionalUserInfo = await fetchUserInfo(access_token);
      if (additionalUserInfo) {
        userInfo.email = userInfo.email || additionalUserInfo.email;
        userInfo.name = userInfo.name || additionalUserInfo.name;
        userInfo.picture = userInfo.picture || additionalUserInfo.picture;
        userInfo.givenName = userInfo.givenName || additionalUserInfo.given_name;
        userInfo.familyName = userInfo.familyName || additionalUserInfo.family_name;
      }
    }

    // Store or update user in user store
    const existingUser = userStore.get(userInfo.sub);
    const user = {
      ...existingUser,
      ...userInfo,
      lastLogin: new Date().toISOString(),
      createdAt: existingUser ? existingUser.createdAt : new Date().toISOString(),
    };
    userStore.set(userInfo.sub, user);

    // Create user session
    req.session.user = {
      sub: user.sub,
      email: user.email,
      name: user.name,
      givenName: user.givenName,
      familyName: user.familyName,
      picture: user.picture,
      emailVerified: user.emailVerified,
    };

    // Store tokens in session (for API calls, token refresh, etc.)
    req.session.tokens = {
      accessToken: access_token,
      refreshToken: refresh_token || null,
      tokenType: token_type,
      expiresAt: expires_in ? Date.now() + (expires_in * 1000) : null,
      idToken: id_token,
    };

    // Clean up OAuth state from session
    delete req.session.oauthState;
    delete req.session.oauthNonce;

    console.log(`User authenticated successfully: ${user.sub} (${user.email})`);

    // Regenerate session to prevent session fixation
    req.session.regenerate((err) => {
      if (err) {
        console.error('Session regeneration error:', err);
      }

      // Restore user data after regeneration
      req.session.user = {
        sub: user.sub,
        email: user.email,
        name: user.name,
        givenName: user.givenName,
        familyName: user.familyName,
        picture: user.picture,
        emailVerified: user.emailVerified,
      };

      req.session.tokens = {
        accessToken: access_token,
        refreshToken: refresh_token || null,
        tokenType: token_type,
        expiresAt: expires_in ? Date.now() + (expires_in * 1000) : null,
        idToken: id_token,
      };

      // Redirect to profile page or dashboard
      res.redirect('/profile');
    });

  } catch (error) {
    console.error('Token exchange error:', error.response?.data || error.message);
    return res.status(500).json({
      error: 'Failed to exchange authorization code for tokens',
      details: error.response?.data || error.message,
    });
  }
});

